    version = 5
    return struct.pack('>HHLLLLBBH', version, count, sys_uptime, unix_secs, unix_nsecs, flow_sequence, engine_type, engine_id, sampling_interval)

def create_netflow_v5_record(flow):
    first_ms = int(flow.first_time * 1000) if flow.first_time else 0
    last_ms = int(flow.last_time * 1000) if flow.last_time else 0
    return struct.pack('>LLLLLLLLHHBBBBHHBBH', flow.src_ip, flow.dst_ip, 0, 0, 0, flow.packet_count, flow.byte_count, first_ms, last_ms, flow.src_port, flow.dst_port, 0, flow.tcp_flags, flow.protocol, 0, 0, 0, 0, 0, 0)

